#include <stdio.h>
#include <stdlib.h>

// Define structure for Disjoint Set Union
typedef struct {
    int* parent;
    int* rank;
    int size;
} DSU;

// Function to create a new DSU
DSU* createDSU(int size) {
    DSU* dsu = (DSU*)malloc(sizeof(DSU));
    dsu->parent = (int*)malloc(size * sizeof(int));
    dsu->rank = (int*)malloc(size * sizeof(int));
    dsu->size = size;
    for (int i = 0; i < size; i++) {
        dsu->parent[i] = i;
        dsu->rank[i] = 0;
    }
    return dsu;
}

// Function to find the parent of a node
int find(DSU* dsu, int node) {
    if (dsu->parent[node] != node) {
        dsu->parent[node] = find(dsu, dsu->parent[node]);
    }
    return dsu->parent[node];
}

// Function to union two nodes
void unionDSU(DSU* dsu, int node1, int node2) {
    int parent1 = find(dsu, node1);
    int parent2 = find(dsu, node2);
    if (parent1 != parent2) {
        if (dsu->rank[parent1] < dsu->rank[parent2]) {
            dsu->parent[parent1] = parent2;
        } else if (dsu->rank[parent1] > dsu->rank[parent2]) {
            dsu->parent[parent2] = parent1;
        } else {
            dsu->parent[parent2] = parent1;
            dsu->rank[parent1]++;
        }
    }
}

// Function to calculate the minimum number of operations
int minOperations(int n, int** connections, int connectionsSize) {
    DSU* dsu = createDSU(n);
    for (int i = 0; i < connectionsSize; i++) {
        unionDSU(dsu, connections[i][0], connections[i][1]);
    }
    int count = 0;
    for (int i = 0; i < n; i++) {
        if (dsu->parent[i] == i) {
            count++;
        }
    }
    if (connectionsSize < n - 1) {
        return -1;
    }
    return count - 1;
}

int main() {
    int n = 6;
    int connectionsSize = 4;
    int** connections = (int**)malloc(connectionsSize * sizeof(int*));
    for (int i = 0; i < connectionsSize; i++) {
        connections[i] = (int*)malloc(2 * sizeof(int));
    }
    connections[0][0] = 0; connections[0][1] = 1;
    connections[1][0] = 0; connections[1][1] = 2;
    connections[2][0] = 0; connections[2][1] = 3;
    connections[3][0] = 1; connections[3][1] = 4;
    printf("%d\n", minOperations(n, connections, connectionsSize));
    return 0;
}

